mapper.select:
SELECT count(*) FROM hm_query.platform_kpi_snapshots

    AND snapshot_date = #{summaryDate}
    AND currency = #{currency}
    AND snapshot_date >= #{startDate}
    AND snapshot_date <= #{endDate}

SELECT
    snapshot_date      as "summaryDate",
    total_orders       as "totalOrders",
    total_revenue      as "totalRevenue",
    avg_order_value    as "avgOrderValue",
    currency           as "currency",
    new_customers      as "newCustomers",
    active_sellers     as "activeSellers",
    cancellation_rate  as "cancellationRate",
    return_rate        as "returnRate"
FROM hm_query.platform_kpi_snapshots

    AND snapshot_date = #{summaryDate}
    AND currency = #{currency}
    AND snapshot_date >= #{startDate}
    AND snapshot_date <= #{endDate}

${orderby} ${pagination}

SELECT count(*) FROM hm_query.product_performance_flat

    AND product_id = #{productId}
    AND period_date >= #{startDate}
    AND period_date <= #{endDate}
    AND product_name LIKE CONCAT('%', #{q}, '%')

SELECT product_id as "productId", product_name as "productName", period_date as "periodDate", views as "views", purchases as "purchases", revenue as "revenue", avg_rating as "avgRating", conversion_rate as "conversionRate" FROM hm_query.product_performance_flat
AND product_id = #{productId} AND period_date >= #{startDate} AND period_date <= #{endDate} AND product_name LIKE CONCAT('%', #{q}, '%')
${orderby} ${pagination}

SELECT snapshot_date as "date", total_revenue as "revenue", total_orders as "orders", avg_order_value as "aov" FROM hm_query.platform_kpi_snapshots
AND snapshot_date >= #{startDate} AND snapshot_date <= #{endDate}
ORDER BY snapshot_date ASC
